-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS tour_legs (
  tour_leg_id                         TEXT                 PRIMARY KEY          -- Stable ordered tour-leg identifier.
);
ALTER TABLE tour_legs ADD COLUMN IF NOT EXISTS candidate_tour TEXT;                                 -- Candidate tour containing the leg.
ALTER TABLE tour_legs ADD COLUMN IF NOT EXISTS from_tour_stop TEXT;                                 -- Ordered visit at the start of the leg.
ALTER TABLE tour_legs ADD COLUMN IF NOT EXISTS to_tour_stop TEXT;                                   -- Ordered visit at the end of the leg.
ALTER TABLE tour_legs ADD COLUMN IF NOT EXISTS travel_edge TEXT;                                    -- Canonical undirected edge traversed by the leg.
ALTER TABLE tour_legs ADD COLUMN IF NOT EXISTS leg_order INTEGER;                                   -- One-based order of the leg.
COMMENT ON TABLE tour_legs IS 'Ordered directed traversal legs bound to canonical undirected travel edges.';
COMMENT ON COLUMN tour_legs.tour_leg_id IS 'Stable ordered tour-leg identifier.';
COMMENT ON COLUMN tour_legs.candidate_tour IS 'Candidate tour containing the leg.';
COMMENT ON COLUMN tour_legs.from_tour_stop IS 'Ordered visit at the start of the leg.';
COMMENT ON COLUMN tour_legs.to_tour_stop IS 'Ordered visit at the end of the leg.';
COMMENT ON COLUMN tour_legs.travel_edge IS 'Canonical undirected edge traversed by the leg.';
COMMENT ON COLUMN tour_legs.leg_order IS 'One-based order of the leg.';

-- ----------------------------------------------------------------------------
-- LocalDegreeBounds: One degree-two lower-bound witness per required stop. Each row names two incident edges and proves all other incident edges are no cheaper than the second selected edge.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS local_degree_bounds (
  local_degree_bound_id               TEXT                 PRIMARY KEY          -- Stable local-bound identifier.
);
ALTER TABLE local_degree_bounds ADD COLUMN IF NOT EXISTS tsp_instance TEXT;                         -- Instance whose tour degree requirement is being bounded.
ALTER TABLE local_degree_bounds ADD COLUMN IF NOT EXISTS instance_stop TEXT;                        -- Required stop receiving the local degree-two bound.
ALTER TABLE local_degree_bounds ADD COLUMN IF NOT EXISTS first_edge TEXT;                           -- Cheapest selected incident edge.
ALTER TABLE local_degree_bounds ADD COLUMN IF NOT EXISTS second_edge TEXT;                          -- Second-cheapest selected incident edge.
COMMENT ON TABLE local_degree_bounds IS 'One degree-two lower-bound witness per required stop. Each row names two incident edges and proves all other incident edges are no cheaper than the second selected edge.';
COMMENT ON COLUMN local_degree_bounds.local_degree_bound_id IS 'Stable local-bound identifier.';
COMMENT ON COLUMN local_degree_bounds.tsp_instance IS 'Instance whose tour degree requirement is being bounded.';
COMMENT ON COLUMN local_degree_bounds.instance_stop IS 'Required stop receiving the local degree-two bound.';
COMMENT ON COLUMN local_degree_bounds.first_edge IS 'Cheapest selected incident edge.';
COMMENT ON COLUMN local_degree_bounds.second_edge IS 'Second-cheapest selected incident edge.';

-- ----------------------------------------------------------------------------
-- IncidentDominanceChecks: Witness rows proving every unselected incident edge is at least as expensive as the second edge named by a LocalDegreeBound.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS incident_dominance_checks (
  incident_dominance_check_id         TEXT                 PRIMARY KEY          -- Stable dominance-check identifier.
);
ALTER TABLE incident_dominance_checks ADD COLUMN IF NOT EXISTS local_degree_bound TEXT;             -- Local lower-bound witness being supported.
ALTER TABLE incident_dominance_checks ADD COLUMN IF NOT EXISTS other_edge TEXT;                     -- Unselected incident edge compared against the second selected edge.
COMMENT ON TABLE incident_dominance_checks IS 'Witness rows proving every unselected incident edge is at least as expensive as the second edge named by a LocalDegreeBound.';
COMMENT ON COLUMN incident_dominance_checks.incident_dominance_check_id IS 'Stable dominance-check identifier.';
COMMENT ON COLUMN incident_dominance_checks.local_degree_bound IS 'Local lower-bound witness being supported.';
COMMENT ON COLUMN incident_dominance_checks.other_edge IS 'Unselected incident edge compared against the second selected edge.';

-- ----------------------------------------------------------------------------
-- InstanceLowerBounds: Global lower bounds obtained by summing certified local degree-two bounds and dividing by two because each tour edge is incident to two stops.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS instance_lower_bounds (
  instance_lower_bound_id             TEXT                 PRIMARY KEY          -- Stable instance-lower-bound identifier.
);
ALTER TABLE instance_lower_bounds ADD COLUMN IF NOT EXISTS tsp_instance TEXT;                       -- Instance receiving the lower bound.
ALTER TABLE instance_lower_bounds ADD COLUMN IF NOT EXISTS bound_kind TEXT;                         -- Kind of reusable lower-bound geometry.
ALTER TABLE instance_lower_bounds ADD COLUMN IF NOT EXISTS required_supplemental_term_count INTEGER;-- Required additive repair terms.
ALTER TABLE instance_lower_bounds ADD COLUMN IF NOT EXISTS supplemental_bound_adjustment NUMERIC;   -- Signed sum of certified repair terms.
ALTER TABLE instance_lower_bounds ADD COLUMN IF NOT EXISTS bound_composition_kind TEXT;             -- Degree-only or degree-plus-repair composition.
COMMENT ON TABLE instance_lower_bounds IS 'Global lower bounds obtained by summing certified local degree-two bounds and dividing by two because each tour edge is incident to two stops.';
COMMENT ON COLUMN instance_lower_bounds.instance_lower_bound_id IS 'Stable instance-lower-bound identifier.';
COMMENT ON COLUMN instance_lower_bounds.tsp_instance IS 'Instance receiving the lower bound.';
COMMENT ON COLUMN instance_lower_bounds.bound_kind IS 'Kind of reusable lower-bound geometry.';
COMMENT ON COLUMN instance_lower_bounds.required_supplemental_term_count IS 'Required additive repair terms.';
COMMENT ON COLUMN instance_lower_bounds.supplemental_bound_adjustment IS 'Signed sum of certified repair terms.';
COMMENT ON COLUMN instance_lower_bounds.bound_composition_kind IS 'Degree-only or degree-plus-repair composition.';

-- ----------------------------------------------------------------------------
-- TSPBoundTerms: Signed additive and constraint terms composing reusable lower-bound certificates.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS tsp_bound_terms (
  tsp_bound_term_id                   TEXT                 PRIMARY KEY          -- Stable TSPBoundTermId identifier.
);
ALTER TABLE tsp_bound_terms ADD COLUMN IF NOT EXISTS bound_certificate TEXT;                        -- Owning instance lower bound.
ALTER TABLE tsp_bound_terms ADD COLUMN IF NOT EXISTS tsp_instance TEXT;                             -- Owning instance.
ALTER TABLE tsp_bound_terms ADD COLUMN IF NOT EXISTS tsp_loop TEXT;                                 -- Loop introducing the term.
ALTER TABLE tsp_bound_terms ADD COLUMN IF NOT EXISTS term_kind TEXT;                                -- Base, insertion, release, parity, or summary term.
ALTER TABLE tsp_bound_terms ADD COLUMN IF NOT EXISTS quantity NUMERIC;                              -- Witnessed quantity.
ALTER TABLE tsp_bound_terms ADD COLUMN IF NOT EXISTS unit_weight NUMERIC;                           -- Cost per unit.
ALTER TABLE tsp_bound_terms ADD COLUMN IF NOT EXISTS sign INTEGER;                                  -- Positive or negative contribution.
ALTER TABLE tsp_bound_terms ADD COLUMN IF NOT EXISTS constraint_kind TEXT;                          -- Constraint witnessed by the term.
ALTER TABLE tsp_bound_terms ADD COLUMN IF NOT EXISTS constraint_value NUMERIC;                      -- Numeric constraint value.
ALTER TABLE tsp_bound_terms ADD COLUMN IF NOT EXISTS counts_toward_adjustment BOOLEAN;              -- Whether TermValue contributes to the supplemental adjustment.
ALTER TABLE tsp_bound_terms ADD COLUMN IF NOT EXISTS is_certified BOOLEAN;                          -- Whether the term has a represented witness.
ALTER TABLE tsp_bound_terms ADD COLUMN IF NOT EXISTS justification TEXT;                            -- Witnessed reason for the term.
COMMENT ON TABLE tsp_bound_terms IS 'Signed additive and constraint terms composing reusable lower-bound certificates.';
COMMENT ON COLUMN tsp_bound_terms.tsp_bound_term_id IS 'Stable TSPBoundTermId identifier.';
COMMENT ON COLUMN tsp_bound_terms.bound_certificate IS 'Owning instance lower bound.';
COMMENT ON COLUMN tsp_bound_terms.tsp_instance IS 'Owning instance.';
COMMENT ON COLUMN tsp_bound_terms.tsp_loop IS 'Loop introducing the term.';
COMMENT ON COLUMN tsp_bound_terms.term_kind IS 'Base, insertion, release, parity, or summary term.';
COMMENT ON COLUMN tsp_bound_terms.quantity IS 'Witnessed quantity.';
COMMENT ON COLUMN tsp_bound_terms.unit_weight IS 'Cost per unit.';
COMMENT ON COLUMN tsp_bound_terms.sign IS 'Positive or negative contribution.';
COMMENT ON COLUMN tsp_bound_terms.constraint_kind IS 'Constraint witnessed by the term.';
COMMENT ON COLUMN tsp_bound_terms.constraint_value IS 'Numeric constraint value.';
COMMENT ON COLUMN tsp_bound_terms.counts_toward_adjustment IS 'Whether TermValue contributes to the supplemental adjustment.';
COMMENT ON COLUMN tsp_bound_terms.is_certified IS 'Whether the term has a represented witness.';
COMMENT ON COLUMN tsp_bound_terms.justification IS 'Witnessed reason for the term.';

-- ----------------------------------------------------------------------------
-- OptimalityCertificates: Finite-instance optimality certificates. Passing requires a valid Hamiltonian witness, a certified lower bound for the same instance, and equality between candidate cost and lower bound.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS optimality_certificates (
  optimality_certificate_id           TEXT                 PRIMARY KEY          -- Stable optimality-certificate identifier.
);
ALTER TABLE optimality_certificates ADD COLUMN IF NOT EXISTS candidate_tour TEXT;                   -- Candidate whose optimality is being certified.
ALTER TABLE optimality_certificates ADD COLUMN IF NOT EXISTS instance_lower_bound TEXT;             -- Certified lower bound compared with the candidate cost.
COMMENT ON TABLE optimality_certificates IS 'Finite-instance optimality certificates. Passing requires a valid Hamiltonian witness, a certified lower bound for the same instance, and equality between candidate cost and lower bound.';
COMMENT ON COLUMN optimality_certificates.optimality_certificate_id IS 'Stable optimality-certificate identifier.';
COMMENT ON COLUMN optimality_certificates.candidate_tour IS 'Candidate whose optimality is being certified.';
COMMENT ON COLUMN optimality_certificates.instance_lower_bound IS 'Certified lower bound compared with the candidate cost.';

-- ----------------------------------------------------------------------------
-- TSPExecutionRuns: Execution attempts against a concrete substrate; blocked and failed runs remain first-class evidence.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS tsp_execution_runs (
  tsp_execution_run_id                TEXT                 PRIMARY KEY          -- Stable TSPExecutionRunId identifier.
);
ALTER TABLE tsp_execution_runs ADD COLUMN IF NOT EXISTS tsp_loop TEXT;                              -- Loop owning the attempt.
ALTER TABLE tsp_execution_runs ADD COLUMN IF NOT EXISTS substrate TEXT;                             -- Execution substrate.
ALTER TABLE tsp_execution_runs ADD COLUMN IF NOT EXISTS attempted_at TEXT;                          -- Attempt timestamp or deterministic run marker.
ALTER TABLE tsp_execution_runs ADD COLUMN IF NOT EXISTS build_command TEXT;                         -- Command attempted.
ALTER TABLE tsp_execution_runs ADD COLUMN IF NOT EXISTS build_succeeded BOOLEAN;                    -- Whether generation succeeded.
ALTER TABLE tsp_execution_runs ADD COLUMN IF NOT EXISTS database_initialized BOOLEAN;               -- Whether the database initialized.
ALTER TABLE tsp_execution_runs ADD COLUMN IF NOT EXISTS conformance_succeeded BOOLEAN;              -- Whether peer conformance passed.
ALTER TABLE tsp_execution_runs ADD COLUMN IF NOT EXISTS status TEXT;                                -- SUCCEEDED, FAILED, or BLOCKED.
ALTER TABLE tsp_execution_runs ADD COLUMN IF NOT EXISTS failure_reason TEXT;                        -- Exact blocking or failure reason.
COMMENT ON TABLE tsp_execution_runs IS 'Execution attempts against a concrete substrate; blocked and failed runs remain first-class evidence.';
COMMENT ON COLUMN tsp_execution_runs.tsp_execution_run_id IS 'Stable TSPExecutionRunId identifier.';
COMMENT ON COLUMN tsp_execution_runs.tsp_loop IS 'Loop owning the attempt.';
COMMENT ON COLUMN tsp_execution_runs.substrate IS 'Execution substrate.';
COMMENT ON COLUMN tsp_execution_runs.attempted_at IS 'Attempt timestamp or deterministic run marker.';
COMMENT ON COLUMN tsp_execution_runs.build_command IS 'Command attempted.';
COMMENT ON COLUMN tsp_execution_runs.build_succeeded IS 'Whether generation succeeded.';
COMMENT ON COLUMN tsp_execution_runs.database_initialized IS 'Whether the database initialized.';
COMMENT ON COLUMN tsp_execution_runs.conformance_succeeded IS 'Whether peer conformance passed.';
COMMENT ON COLUMN tsp_execution_runs.status IS 'SUCCEEDED, FAILED, or BLOCKED.';
COMMENT ON COLUMN tsp_execution_runs.failure_reason IS 'Exact blocking or failure reason.';

