);
ALTER TABLE tsp_inference_states ADD COLUMN IF NOT EXISTS tsp_instance TEXT;                        -- Instance under inference.
ALTER TABLE tsp_inference_states ADD COLUMN IF NOT EXISTS tsp_loop TEXT;                            -- Loop that emitted the state.
