ALTER TABLE tsp_inference_states ADD COLUMN IF NOT EXISTS parent_state_id TEXT;                     -- Prior state identifier without a self-relationship cycle.
ALTER TABLE tsp_inference_states ADD COLUMN IF NOT EXISTS status TEXT;                              -- OPEN, CLOSED, or FIXED_POINT.
ALTER TABLE tsp_inference_states ADD COLUMN IF NOT EXISTS description TEXT;                         -- State meaning.
ALTER TABLE tsp_inference_states ADD COLUMN IF NOT EXISTS alternative_count INTEGER;                -- Alternatives represented in this inference state.
ALTER TABLE tsp_inference_states ADD COLUMN IF NOT EXISTS residual_ambiguity_count INTEGER;         -- Alternatives remaining after deterministic closure.
