COMMENT ON COLUMN tsp_inference_states.tsp_loop IS 'Loop that emitted the state.';
COMMENT ON COLUMN tsp_inference_states.state_kind IS 'Semantic stage.';
COMMENT ON COLUMN tsp_inference_states.parent_state_id IS 'Prior state identifier without a self-relationship cycle.';
COMMENT ON COLUMN tsp_inference_states.status IS 'OPEN, CLOSED, or FIXED_POINT.';
COMMENT ON COLUMN tsp_inference_states.description IS 'State meaning.';
COMMENT ON COLUMN tsp_inference_states.alternative_count IS 'Alternatives represented in this inference state.';
COMMENT ON COLUMN tsp_inference_states.residual_ambiguity_count IS 'Alternatives remaining after deterministic closure.';
COMMENT ON COLUMN tsp_inference_states.branch_decision_count IS 'Mathematical branch decisions used to reach this state.';
COMMENT ON COLUMN tsp_inference_states.value_status IS 'OPEN or CLOSED optimum-value status.';
COMMENT ON COLUMN tsp_inference_states.choice_status IS 'Representative-choice status.';
COMMENT ON COLUMN tsp_inference_states.choice_orbit_id IS 'Residual value-preserving choice orbit identifier.';

