ALTER TABLE tsp_convergence_measurements ADD COLUMN IF NOT EXISTS held_out_instance_count INTEGER;  -- Held-out instances in scope.
ALTER TABLE tsp_convergence_measurements ADD COLUMN IF NOT EXISTS exact_oracle_coverage_pct NUMERIC;-- Percentage of in-scope instances with exact oracle rows.
ALTER TABLE tsp_convergence_measurements ADD COLUMN IF NOT EXISTS value_closed_count INTEGER;       -- Instances whose value closes deterministically.
ALTER TABLE tsp_convergence_measurements ADD COLUMN IF NOT EXISTS route_closed_count INTEGER;       -- Instances whose route class closes deterministically.
ALTER TABLE tsp_convergence_measurements ADD COLUMN IF NOT EXISTS branch_required_count INTEGER;    -- Instances requiring a value-relevant branch after deterministic closure.
ALTER TABLE tsp_convergence_measurements ADD COLUMN IF NOT EXISTS mean_closure_yield_pct NUMERIC;   -- Mean exact route-class elimination percentage.
ALTER TABLE tsp_convergence_measurements ADD COLUMN IF NOT EXISTS max_exact_class_count INTEGER;    -- Largest exact canonical route-class count in the measured corpus.
ALTER TABLE tsp_convergence_measurements ADD COLUMN IF NOT EXISTS basis_growth_count INTEGER;       -- New primitive or operator rows introduced after the basis freeze.
