COMMENT ON COLUMN tsp_convergence_measurements.new_primitive_count IS 'New primitives introduced by this loop.';
COMMENT ON COLUMN tsp_convergence_measurements.derived_alias_count IS 'Named derived concepts retained above the basis.';
COMMENT ON COLUMN tsp_convergence_measurements.physical_table_count IS 'Canonical physical table count at this loop.';
COMMENT ON COLUMN tsp_convergence_measurements.novel_term IS 'Predicate coined or stabilized by the loop.';
COMMENT ON COLUMN tsp_convergence_measurements.prediction_status IS 'NOT_TESTED, EARLY_SUPPORT, COUNTEREVIDENCE, or SUPPORTED_FOR_CURRENT_DOMAIN.';
