COMMENT ON COLUMN tsp_convergence_measurements.active_atom_count IS 'Active relational atom count at this measurement.';
COMMENT ON COLUMN tsp_convergence_measurements.active_operator_count IS 'Active semantic operator count at this measurement.';
COMMENT ON COLUMN tsp_convergence_measurements.physical_table_delta_from_loop610 IS 'Physical table count minus the loop-610 count of forty-five.';
COMMENT ON COLUMN tsp_convergence_measurements.open_frontier_count IS 'Open frontier obligations at this measurement.';
COMMENT ON COLUMN tsp_convergence_measurements.named_concept_count IS 'Versioned concept-registry row count.';
COMMENT ON COLUMN tsp_convergence_measurements.allows_local_expansion IS 'Whether local representational expansion is compatible with the measurement.';
COMMENT ON COLUMN tsp_convergence_measurements.coherence_direction IS 'Multidimensional interpretation without arbitrary scalar weighting.';
COMMENT ON COLUMN tsp_convergence_measurements.development_instance_count IS 'Development instances in scope.';
COMMENT ON COLUMN tsp_convergence_measurements.held_out_instance_count IS 'Held-out instances in scope.';
COMMENT ON COLUMN tsp_convergence_measurements.exact_oracle_coverage_pct IS 'Percentage of in-scope instances with exact oracle rows.';
COMMENT ON COLUMN tsp_convergence_measurements.value_closed_count IS 'Instances whose value closes deterministically.';
COMMENT ON COLUMN tsp_convergence_measurements.route_closed_count IS 'Instances whose route class closes deterministically.';
COMMENT ON COLUMN tsp_convergence_measurements.branch_required_count IS 'Instances requiring a value-relevant branch after deterministic closure.';
COMMENT ON COLUMN tsp_convergence_measurements.mean_closure_yield_pct IS 'Mean exact route-class elimination percentage.';
COMMENT ON COLUMN tsp_convergence_measurements.max_exact_class_count IS 'Largest exact canonical route-class count in the measured corpus.';
COMMENT ON COLUMN tsp_convergence_measurements.basis_growth_count IS 'New primitive or operator rows introduced after the basis freeze.';

-- ----------------------------------------------------------------------------
-- TSPConceptRegistry: Registry of primitive, derived, coined, and historical concepts with explicit basis expressions.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS tsp_concept_registry (
  tsp_concept_id                      TEXT                 PRIMARY KEY          -- Stable TSPConceptId identifier.
);
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS display_name TEXT;                        -- Human-readable concept name.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS concept_kind TEXT;                        -- PRIMITIVE, DERIVED_ALIAS, COINED_PREDICATE, or HISTORICAL_PROJECTION.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS basis_expression TEXT;                    -- Definition over the eight primitive predicates.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS arity INTEGER;                            -- Declared argument count for the concept.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS source_tables TEXT;                       -- Comma-separated historical source projections.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS introduced_by_loop TEXT;                  -- Loop introducing or registering the concept.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS superseded_by_concept TEXT;               -- Canonical coined concept replacing this surface name, when applicable.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS status TEXT;                              -- ACTIVE_PRIMITIVE, ACTIVE_DERIVED, or HISTORICAL_PROJECTION.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS historical_concept_kind TEXT;             -- Concept kind at the time of its historical certificate.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS semantic_category TEXT;                   -- ATOM, OPERATOR, DERIVED, or HISTORICAL.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS reduced_basis_expression TEXT;            -- Current definition over active atoms and operators.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS operator_expression TEXT;                 -- Operators required to derive the concept from atoms.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS reduction_generation INTEGER;             -- Reduction generation introducing the current definition.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS arc_subject_sort TEXT;                    -- Subject sort for a semantic-arc projection.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS arc_label_sort TEXT;                      -- ROLE, MEASURE, MODALITY, or COMPOSED label sort.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS arc_target_sort TEXT;                     -- Target sort for a semantic-arc projection.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS arc_signature TEXT;                       -- Typed subject-label-target signature.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS recoverability_expression TEXT;           -- Projection that recovers the historical concept from the current basis.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS is_recoverable_from_current_basis BOOLEAN;-- Whether the historical or derived concept has an explicit current-basis recovery.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS rewrite_mode TEXT;                        -- Named mode of the current or historical rewrite operator.
ALTER TABLE tsp_concept_registry ADD COLUMN IF NOT EXISTS rewrite_polarity TEXT;                    -- EXPANSIVE, CONTRACTIVE, MIXED, or PARAMETRIC.
COMMENT ON TABLE tsp_concept_registry IS 'Registry of primitive, derived, coined, and historical concepts with explicit basis expressions.';
COMMENT ON COLUMN tsp_concept_registry.tsp_concept_id IS 'Stable TSPConceptId identifier.';
COMMENT ON COLUMN tsp_concept_registry.display_name IS 'Human-readable concept name.';
COMMENT ON COLUMN tsp_concept_registry.concept_kind IS 'PRIMITIVE, DERIVED_ALIAS, COINED_PREDICATE, or HISTORICAL_PROJECTION.';
COMMENT ON COLUMN tsp_concept_registry.basis_expression IS 'Definition over the eight primitive predicates.';
COMMENT ON COLUMN tsp_concept_registry.arity IS 'Declared argument count for the concept.';
COMMENT ON COLUMN tsp_concept_registry.source_tables IS 'Comma-separated historical source projections.';
COMMENT ON COLUMN tsp_concept_registry.introduced_by_loop IS 'Loop introducing or registering the concept.';
COMMENT ON COLUMN tsp_concept_registry.superseded_by_concept IS 'Canonical coined concept replacing this surface name, when applicable.';
COMMENT ON COLUMN tsp_concept_registry.status IS 'ACTIVE_PRIMITIVE, ACTIVE_DERIVED, or HISTORICAL_PROJECTION.';
COMMENT ON COLUMN tsp_concept_registry.historical_concept_kind IS 'Concept kind at the time of its historical certificate.';
COMMENT ON COLUMN tsp_concept_registry.semantic_category IS 'ATOM, OPERATOR, DERIVED, or HISTORICAL.';
COMMENT ON COLUMN tsp_concept_registry.reduced_basis_expression IS 'Current definition over active atoms and operators.';
COMMENT ON COLUMN tsp_concept_registry.operator_expression IS 'Operators required to derive the concept from atoms.';
COMMENT ON COLUMN tsp_concept_registry.reduction_generation IS 'Reduction generation introducing the current definition.';
COMMENT ON COLUMN tsp_concept_registry.arc_subject_sort IS 'Subject sort for a semantic-arc projection.';
COMMENT ON COLUMN tsp_concept_registry.arc_label_sort IS 'ROLE, MEASURE, MODALITY, or COMPOSED label sort.';
COMMENT ON COLUMN tsp_concept_registry.arc_target_sort IS 'Target sort for a semantic-arc projection.';
COMMENT ON COLUMN tsp_concept_registry.arc_signature IS 'Typed subject-label-target signature.';
COMMENT ON COLUMN tsp_concept_registry.recoverability_expression IS 'Projection that recovers the historical concept from the current basis.';
COMMENT ON COLUMN tsp_concept_registry.is_recoverable_from_current_basis IS 'Whether the historical or derived concept has an explicit current-basis recovery.';
COMMENT ON COLUMN tsp_concept_registry.rewrite_mode IS 'Named mode of the current or historical rewrite operator.';
COMMENT ON COLUMN tsp_concept_registry.rewrite_polarity IS 'EXPANSIVE, CONTRACTIVE, MIXED, or PARAMETRIC.';

-- ----------------------------------------------------------------------------
-- SearchMetrics: Quantitative record of how much combinatorial search remains after each represented inference stage.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS search_metrics (
  search_metric_id                    TEXT                 PRIMARY KEY          -- Stable search-metric identifier.
);
ALTER TABLE search_metrics ADD COLUMN IF NOT EXISTS tsp_instance TEXT;                              -- TSP instance being measured.
ALTER TABLE search_metrics ADD COLUMN IF NOT EXISTS tsp_loop TEXT;                                  -- Loop that produced the measurement.
ALTER TABLE search_metrics ADD COLUMN IF NOT EXISTS search_question TEXT;                           -- Exact question whose remaining branch count is being measured.
ALTER TABLE search_metrics ADD COLUMN IF NOT EXISTS candidate_tour TEXT;                            -- Candidate involved when measuring verification rather than route discovery.
ALTER TABLE search_metrics ADD COLUMN IF NOT EXISTS raw_node_count INTEGER;                         -- Required stop count before inference.
ALTER TABLE search_metrics ADD COLUMN IF NOT EXISTS raw_edge_count INTEGER;                         -- Canonical edge count before inference.
ALTER TABLE search_metrics ADD COLUMN IF NOT EXISTS forced_edge_count INTEGER;                      -- Edges forced by represented inference.
ALTER TABLE search_metrics ADD COLUMN IF NOT EXISTS forbidden_edge_count INTEGER;                   -- Edges forbidden by represented inference.
ALTER TABLE search_metrics ADD COLUMN IF NOT EXISTS symmetry_class_count INTEGER;                   -- Route classes after fixing depot and reversal symmetry.
ALTER TABLE search_metrics ADD COLUMN IF NOT EXISTS component_contraction_count INTEGER;            -- Components or clusters contracted.
ALTER TABLE search_metrics ADD COLUMN IF NOT EXISTS branch_count_before INTEGER;                    -- Branches before the current inference stage.
ALTER TABLE search_metrics ADD COLUMN IF NOT EXISTS branch_count_after INTEGER;                     -- Branches after the current inference stage.
ALTER TABLE search_metrics ADD COLUMN IF NOT EXISTS backtrack_count INTEGER;                        -- Backtracks consumed by search.
ALTER TABLE search_metrics ADD COLUMN IF NOT EXISTS residual_ambiguity_count INTEGER;               -- Remaining unresolved route classes or boundary states.
ALTER TABLE search_metrics ADD COLUMN IF NOT EXISTS status TEXT;                                    -- Interpretation of the metric row.
COMMENT ON TABLE search_metrics IS 'Quantitative record of how much combinatorial search remains after each represented inference stage.';
COMMENT ON COLUMN search_metrics.search_metric_id IS 'Stable search-metric identifier.';
COMMENT ON COLUMN search_metrics.tsp_instance IS 'TSP instance being measured.';
COMMENT ON COLUMN search_metrics.tsp_loop IS 'Loop that produced the measurement.';
COMMENT ON COLUMN search_metrics.search_question IS 'Exact question whose remaining branch count is being measured.';
COMMENT ON COLUMN search_metrics.candidate_tour IS 'Candidate involved when measuring verification rather than route discovery.';
COMMENT ON COLUMN search_metrics.raw_node_count IS 'Required stop count before inference.';
COMMENT ON COLUMN search_metrics.raw_edge_count IS 'Canonical edge count before inference.';
COMMENT ON COLUMN search_metrics.forced_edge_count IS 'Edges forced by represented inference.';
COMMENT ON COLUMN search_metrics.forbidden_edge_count IS 'Edges forbidden by represented inference.';
COMMENT ON COLUMN search_metrics.symmetry_class_count IS 'Route classes after fixing depot and reversal symmetry.';
COMMENT ON COLUMN search_metrics.component_contraction_count IS 'Components or clusters contracted.';
COMMENT ON COLUMN search_metrics.branch_count_before IS 'Branches before the current inference stage.';
COMMENT ON COLUMN search_metrics.branch_count_after IS 'Branches after the current inference stage.';
COMMENT ON COLUMN search_metrics.backtrack_count IS 'Backtracks consumed by search.';
COMMENT ON COLUMN search_metrics.residual_ambiguity_count IS 'Remaining unresolved route classes or boundary states.';
COMMENT ON COLUMN search_metrics.status IS 'Interpretation of the metric row.';

-- ----------------------------------------------------------------------------
-- TSPInvariantChecks: Rulebook-native acceptance checks comparing expected raw outcomes to derived candidate-tour fields.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS tsp_invariant_checks (
  tsp_invariant_check_id              TEXT                 PRIMARY KEY          -- Stable invariant-check identifier.
);
ALTER TABLE tsp_invariant_checks ADD COLUMN IF NOT EXISTS display_name TEXT;                        -- Human-readable invariant name.
ALTER TABLE tsp_invariant_checks ADD COLUMN IF NOT EXISTS candidate_tour TEXT;                      -- Candidate tour under test.
ALTER TABLE tsp_invariant_checks ADD COLUMN IF NOT EXISTS expected_hamiltonian_cycle_witness BOOLEAN;-- Expected derived route-validity result.
ALTER TABLE tsp_invariant_checks ADD COLUMN IF NOT EXISTS expected_optimality_proved BOOLEAN;       -- Expected optimality-certificate status.
ALTER TABLE tsp_invariant_checks ADD COLUMN IF NOT EXISTS expected_total_travel_cost NUMERIC;       -- Expected sum of represented valid leg costs.
COMMENT ON TABLE tsp_invariant_checks IS 'Rulebook-native acceptance checks comparing expected raw outcomes to derived candidate-tour fields.';
COMMENT ON COLUMN tsp_invariant_checks.tsp_invariant_check_id IS 'Stable invariant-check identifier.';
COMMENT ON COLUMN tsp_invariant_checks.display_name IS 'Human-readable invariant name.';
COMMENT ON COLUMN tsp_invariant_checks.candidate_tour IS 'Candidate tour under test.';
COMMENT ON COLUMN tsp_invariant_checks.expected_hamiltonian_cycle_witness IS 'Expected derived route-validity result.';
COMMENT ON COLUMN tsp_invariant_checks.expected_optimality_proved IS 'Expected optimality-certificate status.';
COMMENT ON COLUMN tsp_invariant_checks.expected_total_travel_cost IS 'Expected sum of represented valid leg costs.';

